import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon, Badge, Select } from 'decantr/components';

code.example:
function RentRoll({ units, month }) {
  const { div, h1, h2, span, table, thead, tbody, tfoot, tr, th, td } = tags;
  const [selectedMonth, setSelectedMonth] = createSignal(month || new Date().toISOString().slice(0, 7));
  const [statusFilter, setStatusFilter] = createSignal('all');

  const filtered = () => statusFilter() === 'all' ? units : units.filter(u => u.rentStatus === statusFilter());

  const expectedRent = units.reduce((sum, u) => sum + u.rent, 0);
  const collectedRent = units.filter(u => u.rentStatus === 'paid').reduce((sum, u) => sum + u.rent, 0) +
                        units.filter(u => u.rentStatus === 'partial').reduce((sum, u) => sum + u.amountPaid, 0);
  const outstanding = expectedRent - collectedRent - units.filter(u => u.status === 'vacant').reduce((sum, u) => sum + u.rent, 0);
  const vacancyLoss = units.filter(u => u.status === 'vacant').reduce((sum, u) => sum + u.rent, 0);
  const collectionRate = Math.round((collectedRent / (expectedRent - vacancyLoss)) * 100) || 0;

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Rent Roll'),
      div({ class: css('_flex _gap2') },
        Select({ value: selectedMonth(), onchange: e => setSelectedMonth(e.target.value) },
          ...getLast12Months().map(m => tags.option({ value: m.value }, m.label))
        ),
        Button({ variant: 'outline' }, icon('download'), 'Export')
      )
    ),
    div({ class: css('_grid _cols4 _gap4') },
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${expectedRent.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Expected Rent')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgsuccess') }, `$${collectedRent.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, `Collected (${collectionRate}%)`)
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgdanger') }, `$${outstanding.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Outstanding')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgmuted') }, `$${vacancyLoss.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Vacancy Loss')
      )
    ),
    div({ class: css('_flex _gap2 _mb2') },
      Button({ variant: statusFilter() === 'all' ? 'default' : 'ghost', size: 'sm', onclick: () => setStatusFilter('all') }, 'All'),
      Button({ variant: statusFilter() === 'paid' ? 'default' : 'ghost', size: 'sm', onclick: () => setStatusFilter('paid') }, 'Paid'),
      Button({ variant: statusFilter() === 'partial' ? 'default' : 'ghost', size: 'sm', onclick: () => setStatusFilter('partial') }, 'Partial'),
      Button({ variant: statusFilter() === 'unpaid' ? 'default' : 'ghost', size: 'sm', onclick: () => setStatusFilter('unpaid') }, 'Unpaid'),
      Button({ variant: statusFilter() === 'vacant' ? 'default' : 'ghost', size: 'sm', onclick: () => setStatusFilter('vacant') }, 'Vacant')
    ),
    div({ class: css('estate-table _overflow[auto]') },
      table({ class: css('_wfull') },
        thead({},
          tr({ class: css('_bgSurface') },
            th({ class: css('_p3 _textleft _font500') }, 'Property'),
            th({ class: css('_p3 _textleft _font500') }, 'Unit'),
            th({ class: css('_p3 _textleft _font500') }, 'Tenant'),
            th({ class: css('_p3 _tr _font500') }, 'Rent'),
            th({ class: css('_p3 _tr _font500') }, 'Paid'),
            th({ class: css('_p3 _tr _font500') }, 'Balance'),
            th({ class: css('_p3 _tc _font500') }, 'Status'),
            th({ class: css('_p3 _tc _font500') }, 'Days Late')
          )
        ),
        tbody({},
          ...filtered().map((u, i) => {
            const balance = u.rent - (u.amountPaid || 0);
            const statusColor = u.rentStatus === 'paid' ? 'success' : u.rentStatus === 'partial' ? 'warning' : u.status === 'vacant' ? 'default' : 'danger';
            return tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
              td({ class: css('_p3 _textsm') }, u.propertyName),
              td({ class: css('_p3 _font500') }, `Unit ${u.unitNumber}`),
              td({ class: css('_p3 _textsm') }, u.tenantName || span({ class: css('_fgmuted') }, '—')),
              td({ class: css('_p3 _tr _font500') }, `$${u.rent.toLocaleString()}`),
              td({ class: css('_p3 _tr') }, u.amountPaid ? `$${u.amountPaid.toLocaleString()}` : '—'),
              td({ class: css(`_p3 _tr ${balance > 0 ? '_fgdanger' : ''}`) }, balance > 0 ? `$${balance.toLocaleString()}` : '—'),
              td({ class: css('_p3 _tc') }, Badge({ variant: statusColor }, u.status === 'vacant' ? 'vacant' : u.rentStatus)),
              td({ class: css('_p3 _tc') }, u.daysLate > 0 ? span({ class: css('_fgdanger') }, u.daysLate) : '—')
            );
          })
        ),
        tfoot({},
          tr({ class: css('_bgSurface _font500') },
            td({ class: css('_p3'), colspan: 3 }, 'Totals'),
            td({ class: css('_p3 _tr') }, `$${expectedRent.toLocaleString()}`),
            td({ class: css('_p3 _tr _fgsuccess') }, `$${collectedRent.toLocaleString()}`),
            td({ class: css('_p3 _tr _fgdanger') }, `$${outstanding.toLocaleString()}`),
            td({ colspan: 2 })
          )
        )
      )
    )
  );
}

function getLast12Months() {
  const months = [];
  const now = new Date();
  for (let i = 0; i < 12; i++) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    months.push({ value: d.toISOString().slice(0, 7), label: d.toLocaleDateString('en-US', { month: 'long', year: 'numeric' }) });
  }
  return months;
}

