function RentRollSummary({ collected, expected }) {
  const { div, span, h3 } = tags;
  const percentage = Math.round((collected / expected) * 100);

  return link({ href: '/financials/rent-roll', class: css('estate-card _p4 _hoverShadow _trans') },
    div({ class: css('_flex _jcsb _aic _mb3') },
      h3({ class: css('_heading6') }, 'Rent Collection'),
      span({ class: css('_textsm _fgmuted') }, 'This Month')
    ),
    div({ class: css('_flex _jcsb _mb2') },
      span({ class: css('_heading3 _fgsuccess') }, `$${collected.toLocaleString()}`),
      span({ class: css('_fgmuted') }, `of $${expected.toLocaleString()}`)
    ),
    div({ class: css('_h2 _bgBorder _r1 _overflow[hidden]') },
      div({ class: css('_h2 _bgSuccess _r1'), style: `width:${percentage}%` })
    ),
    span({ class: css('_textsm _fgmuted _mt2 _block') }, `${percentage}% collected`)
  );
}

